import React, { useState, useEffect, useContext } from 'react';
import AuthContext from '../context/AuthContext';
import { bookingAPI, resourceAPI } from '../services/api';
import '../styles/Bookings.css';

const Bookings = () => {
  const { user } = useContext(AuthContext);
  const [bookings, setBookings] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [loading, setLoading] = useState(true);
  const [resources, setResources] = useState([]);
  const [formData, setFormData] = useState({
    resourceId: '',
    startTime: '',
    endTime: '',
    purpose: '',
    expectedAttendees: 1,
  });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  useEffect(() => {
    fetchBookings();
    fetchResources();
  }, [user?.id]);

  const fetchBookings = async () => {
    try {
      const response = await bookingAPI.getByUser(user?.id, 0, 10);
      setBookings(response.data.content || response.data);
    } catch (error) {
      console.error('Error fetching bookings:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchResources = async () => {
    try {
      const response = await resourceAPI.getActive();
      setResources(response.data);
    } catch (error) {
      console.error('Error fetching resources:', error);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'expectedAttendees' ? parseInt(value) : value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');

    // Validation
    if (!formData.resourceId) {
      setError('Please select a resource');
      return;
    }
    if (!formData.startTime) {
      setError('Please select a start time');
      return;
    }
    if (!formData.endTime) {
      setError('Please select an end time');
      return;
    }
    if (!formData.purpose || formData.purpose.length < 5) {
      setError('Purpose must be at least 5 characters');
      return;
    }
    if (formData.expectedAttendees < 1) {
      setError('Expected attendees must be at least 1');
      return;
    }

    try {
      // Create booking payload
      const payload = {
        resourceId: formData.resourceId,
        startTime: formData.startTime,
        endTime: formData.endTime,
        purpose: formData.purpose,
        expectedAttendees: formData.expectedAttendees,
        userId: user?.id,
      };

      // Try to create the booking
      const response = await bookingAPI.create(payload);
      
      if (response.status === 201 || response.status === 200) {
        setSuccess('Booking request submitted successfully!');
        setFormData({
          resourceId: '',
          startTime: '',
          endTime: '',
          purpose: '',
          expectedAttendees: 1,
        });
        setShowForm(false);
        fetchBookings();
      }
    } catch (err) {
      console.error('Error creating booking:', err);
      // Handle error responses
      if (err.response?.status === 409) {
        setError('This resource is already booked for the selected time period');
      } else {
        const errorMessage = err.response?.data?.message || err.response?.data?.error || 'Error creating booking';
        setError(typeof errorMessage === 'string' ? errorMessage : 'Error creating booking');
      }
    }
  };

  const handleCancel = async (bookingId) => {
    if (window.confirm('Are you sure you want to cancel this booking?')) {
      try {
        await bookingAPI.cancel(bookingId);
        setSuccess('Booking cancelled successfully');
        fetchBookings();
      } catch (err) {
        setError(err.response?.data?.message || 'Error cancelling booking');
      }
    }
  };

  const getStatusColor = (status) => {
    return {
      PENDING: 'warning',
      APPROVED: 'success',
      REJECTED: 'danger',
      CANCELLED: 'secondary',
    }[status] || 'secondary';
  };

  if (loading) {
    return <div className="loading">Loading bookings...</div>;
  }

  return (
    <div className="bookings-container">
      <div className="bookings-header">
        <h1>My Bookings</h1>
        <button
          className="btn btn-primary"
          onClick={() => setShowForm(!showForm)}
        >
          {showForm ? 'Cancel' : 'New Booking'}
        </button>
      </div>

      {error && <div className="alert alert-error">{error}</div>}
      {success && <div className="alert alert-success">{success}</div>}

      {/* Booking Form */}
      {showForm && (
        <form onSubmit={handleSubmit} className="booking-form">
          <h2>Create New Booking</h2>

          <div className="form-group">
            <label htmlFor="resourceId">Select Resource *</label>
            <select
              id="resourceId"
              name="resourceId"
              value={formData.resourceId}
              onChange={handleInputChange}
              required
            >
              <option value="">Choose a resource...</option>
              {resources.map(resource => (
                <option key={resource._id} value={resource._id}>
                  {resource.name} - {resource.location}
                </option>
              ))}
            </select>
          </div>

          <div className="form-row">
            <div className="form-group">
              <label htmlFor="startTime">Start Date & Time *</label>
              <input
                id="startTime"
                type="datetime-local"
                name="startTime"
                value={formData.startTime}
                onChange={handleInputChange}
                required
              />
            </div>

            <div className="form-group">
              <label htmlFor="endTime">End Date & Time *</label>
              <input
                id="endTime"
                type="datetime-local"
                name="endTime"
                value={formData.endTime}
                onChange={handleInputChange}
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label htmlFor="purpose">Purpose of Booking *</label>
            <textarea
              id="purpose"
              name="purpose"
              value={formData.purpose}
              onChange={handleInputChange}
              placeholder="Describe the purpose of this booking..."
              required
            ></textarea>
          </div>

          <div className="form-group">
            <label htmlFor="expectedAttendees">Expected Attendees</label>
            <input
              id="expectedAttendees"
              type="number"
              name="expectedAttendees"
              value={formData.expectedAttendees}
              onChange={handleInputChange}
              min="1"
            />
          </div>

          <div className="form-actions">
            <button type="submit" className="btn btn-success">Submit Booking</button>
            <button
              type="button"
              className="btn btn-secondary"
              onClick={() => setShowForm(false)}
            >
              Cancel
            </button>
          </div>
        </form>
      )}

      {/* Bookings List */}
      <div className="bookings-list">
        <h2>Your Bookings</h2>
        {bookings.length > 0 ? (
          <div className="bookings-table-container">
            <table className="bookings-table">
              <thead>
                <tr>
                  <th>Resource</th>
                  <th>Start Time</th>
                  <th>End Time</th>
                  <th>Purpose</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {bookings.map(booking => (
                  <tr key={booking._id}>
                    <td>{booking.resourceId}</td>
                    <td>{new Date(booking.startTime).toLocaleString()}</td>
                    <td>{new Date(booking.endTime).toLocaleString()}</td>
                    <td>{booking.purpose}</td>
                    <td>
                      <span className={`badge badge-${getStatusColor(booking.status)}`}>
                        {booking.status}
                      </span>
                    </td>
                    <td>
                      {booking.status === 'PENDING' && (
                        <button
                          className="btn btn-sm btn-danger"
                          onClick={() => handleCancel(booking._id)}
                        >
                          Cancel
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        ) : (
          <p>No bookings yet. Create your first booking!</p>
        )}
      </div>
    </div>
  );
};

export default Bookings;
